//$Id$
import { d3_max } from '../../../core/d3-constants';
import { mathMax } from '../../../core/zc-constants';
import { isArray, invokeFunction } from '../../../utils/zcutils';
import { isFunction } from '../../../utils/function-utils';
import { ScaleRegistry } from '../../../scale/scale-registry';
import { Registry } from '../../../core/zc-registry';

export function evalCorrection(operators, _scale) {
    if (!operators._correction) {
        return [0, 0];
    }
    let corrections = operators._correction.map(op => {
            if (isArray(op)) {
                return op;
            }

            if (isFunction(op)) {
                return invokeFunction(op, this);
            }

            return [op, op];
        }),
        correction = [d3_max(corrections, _ => _[0]), d3_max(corrections, _ => _[1])],
        domain = _scale.config.domain,
        domainOperators = operators.domainOperators || domain.operators || {};

    if (domainOperators.min || domain.hasDefaultMin) {
        correction[0] = 0;
    }
    if (domainOperators.max) {
        correction[1] = 0;
    }

    return [correction[0] || 0, correction[1] || 0];
}
Registry.setComponent('scale.correctionEvaluator', evalCorrection);

export function convertOperatorToBound(operatorC) {
    let scaleComp = this;

    return operatorC.map(_ => {
        let { _type, key } = _;
        if (_type) {
            let bound = ScaleRegistry.get(_type + '-correction-evaluator').call(scaleComp, _) || 0;
            cacheBound(key, bound, scaleComp.chartObj);
            return bound;
        } else {
            return _;
        }
    });
}
Registry.setComponent('scale.operatorCorrectionMapping', convertOperatorToBound);

function cacheBound(key, bound, chart) {
    if (!key || !chart) {
        return;
    }

    let tempBound = isArray(bound) ? bound : [bound, bound],
        cached = chart.cache.correction;

    cached[key] = cached[key] || [0, 0];
    cached[key] = [mathMax(cached[key][0], tempBound[0]), mathMax(cached[key][1], tempBound[1])];
}
